async (page) => {
  var title = "图解 Blaze · 第 3 章 · CriteriaBuilder 查询引擎 — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 3 章 · CriteriaBuilder 查询引擎</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">CriteriaBuilder · WHERE · ORDER BY · 表达式体系 · 动态查询 · JPQL 生成</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder</code> 是 Blaze-Persistence 的核心入口：它以流式 API 构建类型安全的 JPQL 查询，最终由底层 JPA 提供者翻译为原生 SQL。\n    本章从接口继承体系出发，逐一拆解 SELECT、WHERE、ORDER BY、表达式、动态拼接与 JPQL 生成管线，用 <strong style=\"color:#1a1a2e;font-weight:700;\">12 张 Mermaid 图</strong>可视化每一个关键步骤。\n  </p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">CriteriaBuilder 接口继承体系与 FullQueryBuilder 角色</li><li style=\"margin-bottom:4px;font-size:13px;\">SELECT / WHERE / ORDER BY 子句的流式构建方法</li><li style=\"margin-bottom:4px;font-size:13px;\">RestrictionBuilder 谓词树与 JPA Criteria 对比</li><li style=\"margin-bottom:4px;font-size:13px;\">表达式类型体系：路径、函数、子查询、CASE WHEN</li><li style=\"margin-bottom:4px;font-size:13px;\">运行时动态查询拼接策略与参数化查询</li><li style=\"margin-bottom:4px;font-size:13px;\">JPQL 生成管线与调试技巧</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置章节：<span style=\"color:#1e6fff;\">第 2 章 · 项目搭建</span>（CriteriaBuilderFactory 初始化）</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">3.1 CriteriaBuilder API 全景</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 的查询 API 围绕一组精心设计的接口层层继承。理解这棵继承树，才能正确使用链式调用的每一步返回值。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">接口继承体系</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-1 · CriteriaBuilder 核心接口继承体系</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 核心要点：</strong><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder<T></code> 位于继承链顶端，汇聚了 SELECT、WHERE、ORDER BY、分页等所有能力。\n  当你调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">cbf.create(em, Cat.class)</code> 时，返回的就是这个全功能接口实例。\n</section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">接口</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">职责</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">核心方法</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Queryable<T></code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">查询执行</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getResultList()</code>, <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getSingleResult()</code>, <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getQuery()</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WhereBuilder<T></code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">WHERE 条件</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">where()</code>, <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">whereOr()</code>, <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">whereExists()</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OrderByBuilder<T></code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">排序</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">orderByAsc()</code>, <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">orderByDesc()</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SelectBuilder<T></code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">投影字段</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">select()</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">QueryBuilder<T></code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">查询基础</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">from()</code>, <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getQueryString()</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FullQueryBuilder<T></code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">分页 + 复制</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setFirstResult()</code>, <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setMaxResults()</code>, <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">copy()</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder<T></code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">完整查询入口</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">继承全部 + <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getPagedList()</code></td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">链式调用管线</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-2 · 典型查询链式调用流程</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">cbf</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">create</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">c</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">name</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">age</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">cbf.create(em, Cat.class)\"] --> B[\"from(Cat.class, 'c')</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">from(Cat.class, 'c')</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">select('c.name')</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">where('c.age')</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">.gt(3)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">orderByAsc('c.name')</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">setMaxResults(10)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">getResultList()</p></section></td></tr></table></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class, \"c\")<br/>    .select(\"c.name\")<br/>    .where(\"c.age\").gt(3)<br/>    .orderByAsc(\"c.name\")<br/>    .setMaxResults(10);<br/><br/>List&lt;Cat&gt; cats = cb.getResultList();<br/><span style=\"color:#6c7086;font-style:italic;\">// 生成 JPQL: SELECT c.name FROM Cat c WHERE c.age &gt; :param_0</span><br/><span style=\"color:#6c7086;font-style:italic;\">//            ORDER BY c.name ASC NULLS LAST LIMIT 10</span></p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">3.2 SELECT 子句构建</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">SELECT 子句决定查询返回的投影字段。Blaze-Persistence 支持路径表达式、聚合函数、CASE 表达式以及子查询作为 SELECT 项。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">构建管线</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-3 · SELECT 子句构建管线</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">name</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">id</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">status</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">class</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilder<T></p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 调用 select()</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">select('c.name')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">select('COUNT(c.id)')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">selectCase()</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">selectSubquery()</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">as('alias')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">when('c.status', 'eq', 'ACTIVE')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">thenExpression('1')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">otherwiseExpression('0')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">from(Order.class)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">select('COUNT(*)')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">where(...)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">end()</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">FullQueryBuilder</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">代码示例</h3></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">路径 + 聚合投影</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .select(\"o.customer.name\", \"customerName\")<br/>    .select(\"SUM(o.amount)\",   \"totalAmount\")<br/>    .select(\"COUNT(o.id)\",     \"orderCount\")<br/>    .groupBy(\"o.customer.name\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// JPQL: SELECT o.customer.name AS customerName,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//              SUM(o.amount) AS totalAmount,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//              COUNT(o.id) AS orderCount</span><br/><span style=\"color:#6c7086;font-style:italic;\">//       FROM Order o</span><br/><span style=\"color:#6c7086;font-style:italic;\">//       GROUP BY o.customer.name</span></p></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">CASE WHEN 表达式</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .select(\"o.id\")<br/>    .selectCase(\"statusLabel\")<br/>        .when(\"o.status\").eqExpression(\"'SHIPPED'\")<br/>            .thenExpression(\"'已发货'\")<br/>        .when(\"o.status\").eqExpression(\"'PENDING'\")<br/>            .thenExpression(\"'待处理'\")<br/>        .otherwise(\"'未知'\")<br/>    .select(\"o.amount\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// JPQL: SELECT o.id,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//              CASE WHEN o.status = 'SHIPPED' THEN '已发货'</span><br/><span style=\"color:#6c7086;font-style:italic;\">//                   WHEN o.status = 'PENDING' THEN '待处理'</span><br/><span style=\"color:#6c7086;font-style:italic;\">//                   ELSE '未知' END AS statusLabel,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//              o.amount</span><br/><span style=\"color:#6c7086;font-style:italic;\">//       FROM Order o</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-4 · SELECT 子句中的表达式类型占比</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">name</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">3.3 WHERE 条件与谓词</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">WHERE 子句由 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">RestrictionBuilder</code> 链式构建。每次调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">where(\"path\")</code> 返回一个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">RestrictionBuilder</code>，支持 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">eq()</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">gt()</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">like()</code> 等操作符。多个条件默认以 AND 组合。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">谓词树构建</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-5 · RestrictionBuilder 谓词树构建流程</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">age</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">name</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">status</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilder\"] --> W1[\"where('c.age')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">where('c.age')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">RestrictionBuilder</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.gt(18)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">返回 CriteriaBuilder</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">where('c.name')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">RestrictionBuilder</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.like().value('%test%').noEscape()</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">返回 CriteriaBuilder</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">where('c.status')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">RestrictionBuilder</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.in('ACTIVE','PENDING')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">返回 CriteriaBuilder</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 内部谓词树</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">AND</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c.age > 18</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c.name LIKE '%test%'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c.status IN ('ACTIVE','PENDING')</p></section></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">操作符方法</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">JPQL 输出</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">说明</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.eq(value)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">= :param</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">等于</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.notEq(value)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\"><> :param</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">不等于</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.gt(value)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">> :param</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">大于</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.ge(value)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">>= :param</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">大于等于</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.lt(value)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">< :param</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">小于</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.le(value)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\"><= :param</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">小于等于</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.between(a, b)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">BETWEEN :a AND :b</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">范围</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.like()</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LIKE :param</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">模糊匹配</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.in(values)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">IN (:v1, :v2, ...)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">包含</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.isNull()</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">IS NULL</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">空值判断</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.isNotNull()</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">IS NOT NULL</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">非空判断</td></tr></table></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">OR 组合与嵌套</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class, \"c\")<br/>    .whereOr()<br/>        .where(\"c.name\").like().value(\"Tom%\").noEscape()<br/>        .where(\"c.name\").like().value(\"Jerry%\").noEscape()<br/>    .endOr()<br/>    .where(\"c.age\").gt(1);<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// JPQL: ... WHERE (c.name LIKE 'Tom%' OR c.name LIKE 'Jerry%')</span><br/><span style=\"color:#6c7086;font-style:italic;\">//              AND c.age &gt; 1</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-6 · AND / OR 嵌套谓词逻辑树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">age</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">name</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">WHERE 根节点 AND\"] --> OR_GROUP[\"OR 组</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OR 组</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c.age > 1</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c.name LIKE 'Tom%'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c.name LIKE 'Jerry%'</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">JPA Criteria vs Blaze-Persistence 对比</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// JPA Criteria API — 冗长且难以阅读</span><br/>CriteriaBuilder jcb = em.getCriteriaBuilder();<br/>CriteriaQuery&lt;Cat&gt; cq = jcb.createQuery(Cat.class);<br/>Root&lt;Cat&gt; root = cq.from(Cat.class);<br/>cq.where(<br/>    jcb.and(<br/>        jcb.gt(root.get(\"age\"), 3),<br/>        jcb.like(root.get(\"name\"), \"T%\"),<br/>        jcb.in(root.get(\"status\"))<br/>            .value(\"ACTIVE\")<br/>            .value(\"PENDING\")<br/>    )<br/>);<br/>cq.orderBy(jcb.asc(root.get(\"name\")));<br/>List&lt;Cat&gt; result = em.createQuery(cq)<br/>    .setMaxResults(10)<br/>    .getResultList();</p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Blaze-Persistence — 流式且可读</span><br/>List&lt;Cat&gt; result = cbf.create(em, Cat.class, \"c\")<br/>    .where(\"c.age\").gt(3)<br/>    .where(\"c.name\").like().value(\"T%\").noEscape()<br/>    .where(\"c.status\").in(\"ACTIVE\", \"PENDING\")<br/>    .orderByAsc(\"c.name\")<br/>    .setMaxResults(10)<br/>    .getResultList();</p></section>\n<section style=\"margin:12px 0 20px;\"><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">15</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">JPA Criteria 行数</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">7</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">Blaze-Persistence 行数</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">53%</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">代码量减少</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">动态 WHERE 构建</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class, \"c\");<br/><br/>if (nameFilter != null) {<br/>    cb.where(\"c.name\").like().value(\"%\" + nameFilter + \"%\").noEscape();<br/>}<br/>if (minAge != null) {<br/>    cb.where(\"c.age\").ge(minAge);<br/>}<br/>if (statuses != null &amp;&amp; !statuses.isEmpty()) {<br/>    cb.where(\"c.status\").in(statuses);<br/>}<br/><br/>return cb.getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 动态拼接的优势：</strong>不需要像 JPA Criteria 那样预先构建 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Predicate[]</code>，\n  直接按条件追加 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">where()</code> 即可，框架自动以 AND 组合。这使得条件查询代码更加直观。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">3.4 ORDER BY 与 LIMIT / OFFSET</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">排序和分页是查询的最后一环。Blaze-Persistence 提供了精细的 NULL 值排序控制和标准分页 API。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-7 · ORDER BY + LIMIT/OFFSET 查询执行流程</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">构建阶段</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">CriteriaBuilder\"] --> B[\"orderByAsc('c.name')</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">orderByAsc('c.name')</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">orderByDesc('c.createdAt')</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">setFirstResult(20)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">setMaxResults(10)</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">生成阶段</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">getQueryString()</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JPQL 渲染</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">执行阶段</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JPA Provider</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SQL: ORDER BY ... LIMIT 10 OFFSET 20</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">ResultSet</p></section></td></tr></table></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class, \"c\")<br/>    .orderByAsc(\"c.name\")<br/>    .orderByDesc(\"c.createdAt\")<br/>    .orderBy(\"c.id\", true, true)   <span style=\"color:#6c7086;font-style:italic;\">// ASC, NULLS FIRST</span><br/>    .setFirstResult(20)             <span style=\"color:#6c7086;font-style:italic;\">// OFFSET 20</span><br/>    .setMaxResults(10);             <span style=\"color:#6c7086;font-style:italic;\">// LIMIT 10</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// JPQL: ... ORDER BY c.name ASC NULLS LAST,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//                     c.createdAt DESC NULLS LAST,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//                     c.id ASC NULLS FIRST</span></p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">方法</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">说明</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">默认 NULL 处理</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">orderByAsc(path)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">升序排列</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">NULLS LAST</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">orderByDesc(path)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">降序排列</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">NULLS LAST</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">orderBy(path, asc, nullsFirst)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">完全控制排序方向和 NULL 位置</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">由参数决定</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setFirstResult(int)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">偏移量（跳过前 N 行）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">—</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setMaxResults(int)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">最大返回行数</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">—</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ Offset 分页的性能陷阱：</strong>当 offset 很大时，数据库仍然需要扫描并丢弃前 N 行。\n  对于深度分页场景，请参考 <span style=\"color:#1e6fff;\">第 10 章 · Keyset 分页</span>以获取 O(1) 分页方案。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">3.5 表达式体系</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 内部维护了一套表达式 AST（抽象语法树），每个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">select()</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">where()</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">orderBy()</code> 中的字符串都会被解析为对应的表达式节点。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">表达式类型继承</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-8 · Blaze-Persistence 表达式类型继承体系</p><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">Expression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;abstract&gt;&gt; · accept · toString</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">PathExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">String path · List~PathElement~ elements · getField</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">FunctionExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">String functionName · List~Expression~ arguments · getFunctionName</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">SubqueryExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">SubqueryBuilder builder · getSubquery</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">ParameterExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">String name · Object value · getName</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">GeneralCaseExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">List~WhenClause~ whenClauses · Expression defaultExpr</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">SimpleCaseExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">Expression caseOperand · List~WhenClause~ whenClauses</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">ArithmeticExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">Expression left · Expression right · ArithmeticOp operator</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">AggregateExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">String function · Expression argument · boolean distinct</p></section></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">表达式类型</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">示例</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">解析结果</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">路径表达式</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">c.owner.name</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">PathExpression [c → owner → name]</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">函数表达式</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SIZE(c.kittens)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">FunctionExpression(\"SIZE\", [PathExpr])</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">聚合表达式</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">COUNT(c.id)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">AggregateExpression(\"COUNT\", PathExpr)</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">参数表达式</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">:minAge</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">ParameterExpression(\"minAge\")</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">算术表达式</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">c.price * c.quantity</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">ArithmeticExpression(*, left, right)</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">CASE 表达式</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CASE WHEN ... THEN ...</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">GeneralCaseExpression</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">子查询表达式</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">(SELECT COUNT(*) ...)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">SubqueryExpression</td></tr></table></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">常用函数表达式</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// SIZE — 集合大小</span><br/>cb.select(\"SIZE(c.kittens)\", \"kittenCount\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// COUNT — 聚合计数</span><br/>cb.select(\"COUNT(c.id)\", \"total\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// SUM / AVG — 数值聚合</span><br/>cb.select(\"SUM(o.amount)\", \"totalAmount\")<br/>  .select(\"AVG(o.amount)\", \"avgAmount\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// COALESCE — 空值替换</span><br/>cb.select(\"COALESCE(c.nickname, c.name)\", \"displayName\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// CONCAT — 字符串连接</span><br/>cb.select(\"CONCAT(c.firstName, ' ', c.lastName)\", \"fullName\");</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">CASE WHEN 表达式构建</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-9 · CASE WHEN 表达式构建流水线</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">o</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">status</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">selectCase('alias')\"] --> W1[\"when('o.status')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">when('o.status')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.eqExpression('SHIPPED')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">thenExpression('已发货')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">when('o.status')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.eqExpression('PENDING')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">thenExpression('待处理')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">when('o.status')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.eqExpression('CANCELLED')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">thenExpression('已取消')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">otherwise('未知')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">GeneralCaseExpression</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">📝 提示：</strong><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">eqExpression()</code> 接受 JPQL 表达式字符串，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">eq()</code> 接受 Java 值并自动参数化。\n  如果比较的是常量字符串，使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">eqExpression(\"'VALUE'\")</code>；如果是变量，使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">eq(variable)</code>。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">3.6 动态查询拼接</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">在实际业务中，查询条件往往根据用户输入或业务逻辑动态变化。Blaze-Persistence 的流式 API 天然支持条件拼接——只要不调用某个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">where()</code>，该条件就不会出现在最终 JPQL 中。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-10 · 动态查询决策树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">name</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">age</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">status</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">创建 CriteriaBuilder</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ nameFilter != null?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">where('c.name').like(nameFilter)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ minAge != null?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">where('c.age').ge(minAge)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ statuses 非空?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">where('c.status').in(statuses)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ sortField != null?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">orderByAsc(sortField)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">getResultList()</p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public List&lt;Cat&gt; searchCats(CatSearchCriteria criteria) {<br/>    CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class, \"c\");<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 动态 WHERE</span><br/>    if (criteria.getName() != null) {<br/>        cb.where(\"c.name\").like()<br/>          .value(\"%\" + criteria.getName() + \"%\").noEscape();<br/>    }<br/>    if (criteria.getMinAge() != null) {<br/>        cb.where(\"c.age\").ge(criteria.getMinAge());<br/>    }<br/>    if (criteria.getMaxAge() != null) {<br/>        cb.where(\"c.age\").le(criteria.getMaxAge());<br/>    }<br/>    if (criteria.getStatuses() != null) {<br/>        cb.where(\"c.status\").in(criteria.getStatuses());<br/>    }<br/>    if (criteria.getOwnerId() != null) {<br/>        cb.where(\"c.owner.id\").eq(criteria.getOwnerId());<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 动态排序</span><br/>    if (criteria.getSortField() != null) {<br/>        if (criteria.isSortAsc()) {<br/>            cb.orderByAsc(\"c.\" + criteria.getSortField());<br/>        } else {<br/>            cb.orderByDesc(\"c.\" + criteria.getSortField());<br/>        }<br/>    } else {<br/>        cb.orderByAsc(\"c.id\");<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 分页</span><br/>    if (criteria.getPageSize() &gt; 0) {<br/>        cb.setFirstResult(criteria.getPage() * criteria.getPageSize());<br/>        cb.setMaxResults(criteria.getPageSize());<br/>    }<br/><br/>    return cb.getResultList();<br/>}</p></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">参数化查询</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class, \"c\")<br/>    .where(\"c.age\").gtExpression(\":minAge\")<br/>    .where(\"c.name\").like().expression(\":namePattern\")<br/>    .setParameter(\"minAge\", 3)<br/>    .setParameter(\"namePattern\", \"%Tom%\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 参数化查询使 JPA 提供者可以缓存查询计划</span><br/><span style=\"color:#6c7086;font-style:italic;\">// JPQL: ... WHERE c.age &gt; :minAge AND c.name LIKE :namePattern</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-11 · 参数化 vs 内联值的查询计划复用</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">内联值</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">where('c.age').gt(3)\"] --> B1[\"JPQL: c.age > 3</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JPQL: c.age > 3</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">where('c.age').gt(5)\"] --> B2[\"JPQL: c.age > 5</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JPQL: c.age > 5</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">查询计划 A</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">查询计划 B</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">参数化</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">where('c.age').gtExpression(':minAge')\"] --> B3[\"JPQL: c.age > :minAge</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JPQL: c.age > :minAge</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">查询计划 X（可复用）</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">setParameter('minAge', 3)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">setParameter('minAge', 5)</p></section></td></tr></table></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 最佳实践：</strong>对于高频查询，尽量使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">:param</code> 参数化表达式而非内联值。\n  这样 JPA 提供者（Hibernate）能复用同一份查询计划缓存，显著减少 JPQL → SQL 的解析开销。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">3.7 JPQL 生成与调试</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">CriteriaBuilder 的最终输出是 JPQL 字符串，再由 JPA 提供者翻译为目标数据库的原生 SQL。理解这条渲染管线有助于排查查询问题。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-12 · API 调用 → JPQL → SQL 全链路渲染管线</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CriteriaBuilder</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">表达式 AST</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">JPQL 渲染器</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">JPA Provider</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">使用 getQueryString() 调试</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class, \"c\")<br/>    .where(\"c.age\").gt(3)<br/>    .where(\"c.owner.name\").like().value(\"%Alice%\").noEscape()<br/>    .orderByAsc(\"c.name\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 在执行前获取 JPQL 用于调试</span><br/>String jpql = cb.getQueryString();<br/>System.out.println(\"Generated JPQL: \" + jpql);<br/><span style=\"color:#6c7086;font-style:italic;\">// 输出: SELECT c FROM Cat c JOIN c.owner owner_1</span><br/><span style=\"color:#6c7086;font-style:italic;\">//        WHERE c.age &gt; :param_0 AND owner_1.name LIKE :param_1</span><br/><span style=\"color:#6c7086;font-style:italic;\">//        ORDER BY c.name ASC NULLS LAST</span><br/><br/>List&lt;Cat&gt; result = cb.getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:8px;padding:14px 16px;margin:14px 0 20px;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;letter-spacing:.5px;margin-bottom:8px;\">🔍 实战案例</p><p style=\"font-size:14px;font-weight:600;color:#1e6fff;margin:0 0 6px;\">日志配置：查看生成的 SQL</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;line-height:1.7;\">在 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">application.yml</code> 中开启 Hibernate SQL 日志和 Blaze-Persistence 调试：</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">logging:<br/>  level:<br/>    org.hibernate.SQL: DEBUG<br/>    org.hibernate.type.descriptor.sql.BasicBinder: TRACE<br/>    com.blazebit.persistence: DEBUG<br/><br/><span style=\"color:#6c7086;font-style:italic;\"># 或者在 persistence.xml</span><br/>&lt;property name=\"hibernate.show_sql\" value=\"true\"/&gt;<br/>&lt;property name=\"hibernate.format_sql\" value=\"true\"/&gt;</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-13 · getQueryString() 调试工作流</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">构建 CriteriaBuilder\"] --> B[\"getQueryString()</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">getQueryString()</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ JPQL 是否符合预期?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">getResultList() 执行</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">检查 where/select/join</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 是路径错误?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">修正路径表达式</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 是 JOIN 问题?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">检查隐式 JOIN 生成</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">检查参数绑定</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">开启 Hibernate SQL 日志</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ SQL 是否符合预期?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">完成 ✓</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">检查 JPA Provider 翻译</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">3.8 陷阱与限制</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">使用 CriteriaBuilder 时有一些常见的陷阱需要注意。本节列出最常见的问题和解决方案。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">隐式 JOIN 与路径解析</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-14 · 隐式 JOIN 生成机制</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">应用代码</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">where('c.owner.address.city').eq('上海')</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">Blaze</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">解析 c.owner\"] --> J1[\"隐式 JOIN Cat.owner</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">隐式 JOIN Cat.owner</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">解析 owner.address</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">隐式 JOIN Owner.address</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">解析 address.city</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">字段引用 city</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">生成的</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">FROM Cat c<br/>JOIN c.owner owner_1<br/>JOIN owner_1.address address_1<br/>WHERE address_1.city = :param_0</p></section></td></tr></table></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ 隐式 JOIN 陷阱：</strong>路径 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">c.owner.address.city</code> 会自动生成 2 个 JOIN。\n  如果多个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">where()</code> 使用同一前缀路径（如 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">c.owner.name</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">c.owner.age</code>），\n  Blaze-Persistence 会智能复用同一个 JOIN，但跨不同关联路径时可能产生意料之外的笛卡尔积。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">常见陷阱一览</h3></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">陷阱</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">症状</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">解决方案</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">隐式 JOIN 重复</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">查询结果行数比预期多</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">DISTINCT</code> 或显式 JOIN</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">参数类型不匹配</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">运行时 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">IllegalArgumentException</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">确保 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">eq()</code> 的参数类型与实体字段类型一致</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">LIKE 未转义</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">通配符 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">%</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">_</code> 被当作匹配符</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.like().value(val).noEscape()</code> 或手动转义</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">NULL 比较</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">where(\"c.name\").eq(null)</code> 不生效</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.isNull()</code> 代替 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.eq(null)</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">集合 IN 空列表</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.in(emptyList)</code> 抛异常</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">调用前判空，或使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">1=0</code> 短路</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">查询计划缓存膨胀</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Hibernate QueryPlanCache 内存占用过高</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">参数化查询而非内联值</td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">JPA 提供者差异</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 3-15 · Hibernate vs EclipseLink JPQL 翻译差异</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Blaze</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Persistence</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">name</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Blaze-Persistence JPQL<br/>SELECT c FROM Cat c<br/>ORDER BY c.name ASC NULLS LAST<br/>LIMIT 10 OFFSET 20</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Hibernate 翻译</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EclipseLink 翻译</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT c.* FROM cat c<br/>ORDER BY c.name ASC NULLS LAST<br/>LIMIT 10 OFFSET 20</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT c.* FROM cat c<br/>ORDER BY CASE WHEN c.name IS NULL<br/>THEN 1 ELSE 0 END, c.name ASC<br/>LIMIT 10 OFFSET 20</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PostgreSQL ✓ 原生 NULLS LAST</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">MySQL — 模拟 NULLS LAST</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">EclipseLink 注意事项</strong></p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Hibernate 优势</strong></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">📚 参考：</strong>Hibernate ORM 的 JPQL 翻译规则详见\n  <span style=\"color:#1e6fff;\">Hibernate User Guide — HQL/JPQL</span>。\n  Blaze-Persistence 对不同 JPA 提供者的兼容性处理记录在\n  <span style=\"color:#1e6fff;\">Core Manual — Provider Notes</span>。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">查询计划缓存最佳配置</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\"># Hibernate 查询计划缓存调优</span><br/>hibernate.query.plan_cache_max_size=2048<br/>hibernate.query.plan_parameter_metadata_max_size=128<br/><br/><span style=\"color:#6c7086;font-style:italic;\"># 监控缓存命中率</span><br/><span style=\"color:#6c7086;font-style:italic;\"># 启用 Hibernate 统计</span><br/>hibernate.generate_statistics=true</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">📝 经验法则：</strong>如果应用有超过 500 种不同的查询结构（去参数化后），\n  应该检查是否存在内联值导致的缓存膨胀。使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getQueryString()</code> 输出并归一化对比，\n  识别可参数化的查询。\n</section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 📝 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder<T></code> 继承自 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FullQueryBuilder</code>，汇聚 SELECT / WHERE / ORDER BY / 分页等全部查询能力</li><li style=\"margin-bottom:5px;font-size:14px;\">SELECT 子句支持路径、聚合、CASE WHEN 和子查询四种表达式类型</li><li style=\"margin-bottom:5px;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">RestrictionBuilder</code> 链式 API 大幅简化 WHERE 条件构建，相比 JPA Criteria 减少 50%+ 代码量</li><li style=\"margin-bottom:5px;font-size:14px;\">ORDER BY 支持精细的 NULLS FIRST / LAST 控制；LIMIT / OFFSET 通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setFirstResult</code> / <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setMaxResults</code> 实现</li><li style=\"margin-bottom:5px;font-size:14px;\">表达式 AST 体系支持路径、函数、聚合、参数、算术和 CASE 等节点类型</li><li style=\"margin-bottom:5px;font-size:14px;\">动态查询通过条件式 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">where()</code> 调用天然实现，无需预构建 Predicate 数组</li><li style=\"margin-bottom:5px;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getQueryString()</code> 是调试的第一手段；配合 Hibernate SQL 日志可追踪完整管线</li><li style=\"margin-bottom:5px;font-size:14px;\">注意隐式 JOIN 重复、NULL 比较、空 IN 列表和查询计划缓存膨胀等常见陷阱</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">\n    下一章 → <span style=\"color:#1e6fff;\">第 4 章 · Entity View 基础</span>：\n    从 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityView</code> 注解出发，学习如何将 CriteriaBuilder 查询的结果自动投影为类型安全的 DTO 接口。\n  </p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 3 章 · CriteriaBuilder 查询引擎</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}